#include <vector>
#include <set>
#include <unordered_map>
#include <queue>
using namespace std;

class Fenw {
public:
    vector<long long> tree;
    int n;

    Fenw(int _n) : n(_n) {
        tree.resize(n+1, 0);
    }

    void update(int idx, long long delta) {
        idx++;
        while (idx <= n) {
            tree[idx] += delta;
            idx += idx & -idx;
        }
    }

    long long prefix_query(int idx) {
        idx++;
        long long s = 0;
        while (idx) {
            s += tree[idx];
            idx -= idx & -idx;
        }
        return s;
    }

    long long range_query(int l, int r) {
        if (l == 0) {
            return prefix_query(r);
        }
        return prefix_query(r) - prefix_query(l-1);
    }
};

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    set<long long> distinct;
    distinct.insert(1);
    for (long long x : nums) distinct.insert(x);
    for (auto q : queries) {
        if (q.size() >= 3 && q[0] == 2) {
            distinct.insert(q[2]);
        }
    }

    unordered_map<long long, int> depth_map;
    depth_map[1] = 0;

    for (long long x : distinct) {
        if (depth_map.find(x) != depth_map.end()) continue;
        vector<long long> path;
        long long curr = x;
        while (depth_map.find(curr) == depth_map.end()) {
            path.push_back(curr);
            if (curr == 1) 
                break;
            curr = __builtin_popcountll(curr);
        }
        int d = depth_map[curr];
        for (int i = path.size()-1; i >= 0; i--) {
            d = 1 + d;
            depth_map[path[i]] = d;
        }
    }

    int n = nums.size();
    vector<Fenw> trees;
    for (int i = 0; i < 6; i++) {
        trees.push_back(Fenw(n));
    }

    vector<int> depth_arr(n, 0);
    for (int i = 0; i < n; i++) {
        depth_arr[i] = depth_map[nums[i]];
        if (depth_arr[i] >= 0 && depth_arr[i] <= 5) {
            trees[depth_arr[i]].update(i, 1);
        }
    }

    vector<long long> ans;
    for (auto& q : queries) {
        if (q[0] == 1) {
            long long l = q[1];
            long long r = q[2];
            long long k = q[3];
            if (k < 0 || k > 5) {
                ans.push_back(0);
            } else {
                long long cnt = trees[k].range_query(l, r);
                ans.push_back(cnt);
            }
        } else if (q[0] == 2) {
            long long idx = q[1];
            long long val = q[2];
            int old_depth = depth_arr[idx];
            if (old_depth >= 0 && old_depth <= 5) {
                trees[old_depth].update(idx, -1);
            }
            int new_depth = depth_map[val];
            depth_arr[idx] = new_depth;
            if (new_depth >= 0 && new_depth <= 5) {
                trees[new_depth].update(idx, 1);
            }
        }
    }
    return ans;
}
