    vector<int> tree;
    Fenw(int _n) : n(_n), tree(n+2, 0) {}

    void update(int idx, int delta) {
        idx++;
        while (idx <= n) {
            tree[idx] += delta;
            idx += (idx & -idx);
        }
    }

    int query(int idx) {
        idx++;
        int s = 0;
        while (idx > 0) {
            s += tree[idx];
            idx -= (idx & -idx);
        }
        return s;
    }

    int range_query(int l, int r) {
