vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    unordered_map<long long, int> memo_depth;
    memo_depth[1] = 0;

    function<int(long long)> depth_func = [&](long long x) -> int {
        if (memo_depth.find(x) != memo_depth.end()) 
            return memo_depth[x];
        int cnt = __builtin_popcountll((unsigned long long)(x));
        int d = 1 + depth_func(cnt);
        memo_depth[x] = d;
        return d;
